parameters.body:
=BEGIN:VCALENDAR
VERSION:2.0
PRODID:-//n8n//Nextcloud//EN
BEGIN:VTODO
UID:{{ $now.toSeconds() }}
DTSTAMP:{{ $now.toFormat('yyyyMMdd\THHmmss\Z') }}
SUMMARY:{{ $json.body.title }}
{{ $json.body.description ? 'DESCRIPTION:' + $json.body.description + '\n' : '' }}{{ $json.body.due ? 'DTEND:' + $json.body.due + '\n' : '' }}{{ $json.body.priority ? 'PRIORITY:' + $json.body.priority + '\n' : '' }}STATUS:NEEDS-ACTION
END:VTODO
END:VCALENDAR

parameters.jsCode:
const response = $input.first();
const body = response.json.body || response.json;

if (response.json.statusCode === 201 || response.json.statusCode === 204 || !response.json.error) {
  return [{
    json: {
      success: true,
      message: 'Task created successfully!',
      task: {
        title: $('Webhook - Create Task').first().json.body.title,
        description: $('Webhook - Create Task').first().json.body.description || null,
        due: $('Webhook - Create Task').first().json.body.due || null
      }
    }
  }];
} else {
  return [{
    json: {
      success: false,
      message: 'Failed to create task',
      error: body
    }
  }];
}
